"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import dynamic from "next/dynamic";
import Image from "next/image";
import { ConnectButton } from '@rainbow-me/rainbowkit';

const NavbarComponent = () => {
  const pathname = usePathname();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return <div className="w-full h-[90px] fixed top-0 z-[100]" />;
  }

  const isActive = (path: string) => {
    if (path === "/") return pathname === "/";
    return pathname.startsWith(path);
  };

  const baseLinkStyle = "transition-all duration-200 hover:scale-105 cursor-pointer";
  const inactiveStyle = "text-slate-300 hover:text-emerald-400";
  const activeStyle = "text-emerald-400 font-bold drop-shadow-[0_0_8px_rgba(34,197,94,0.5)] scale-105";

  const getLinkClassName = (path: string) => {
    return `${baseLinkStyle} ${isActive(path) ? activeStyle : inactiveStyle}`;
  };

  return (
    <div className="w-full h-[90px] fixed top-0 z-[100] flex justify-center items-center pointer-events-none">
      <div className="relative pointer-events-auto w-[96%] max-w-[1250px] h-[80px] rounded-3xl group transition-all duration-300">
        {/* Glass Layer (Sibling) - This won't isolate the blend mode */}
        <div className="absolute inset-0 rounded-3xl backdrop-blur-md bg-[#050a07]/85 border border-emerald-400/30 shadow-[0_0_20px_rgba(16,185,129,0.15)] pointer-events-none group-hover:border-emerald-400/50 transition-all duration-300"></div>

        {/* Content Layer (Sibling) */}
        <div className="relative h-full flex items-center justify-between px-6 md:px-10">
          {/* LOGO FINARA (IMAGEM) */}
          <Link href="/" className="h-20 flex items-center justify-center" style={{ isolation: 'auto' }}>
            <img
              src="/logo.png"
              alt="Finara Logo"
              style={{
                mixBlendMode: 'screen',
                filter: 'url(#remove-black) brightness(1.6) contrast(1.3)'
              }}
              className="h-20 w-auto object-contain hover:scale-110 transition-transform duration-300 transform-gpu cursor-pointer"
            />
          </Link>

          {/* MENU DESKTOP */}
          <nav className="hidden md:flex justify-center flex-1 gap-14 text-[15px] font-semibold tracking-wide">
            <Link href="/lend" className={getLinkClassName("/lend")}>
              Lend
            </Link>
            <Link href="/trade" className={getLinkClassName("/trade")}>
              Trade
            </Link>
            <Link href="/yield" className={getLinkClassName("/yield")}>
              Yield
            </Link>
          </nav>

          {/* BOTÃO CONECTAR CARTEIRA REAL */}
          <div className="flex items-center gap-4">
            <div className="hidden md:block">
              <ConnectButton showBalance={false} accountStatus="address" chainStatus="icon" />
            </div>

            <button
              className="md:hidden text-white focus:outline-none text-2xl"
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            >
              ☰
            </button>
          </div>
        </div>
      </div>

      {/* MENU MOBILE */}
      {isMobileMenuOpen && (
        <div className="pointer-events-auto absolute top-[85px] w-[90%] max-w-[400px] rounded-2xl bg-[#050a07]/95 border border-emerald-500/10 backdrop-blur-xl p-6 flex flex-col items-center text-white shadow-2xl animate-in slide-in-from-top-5">
          <Link href="/lend" className="py-3 w-full text-center hover:bg-emerald-500/5 rounded-lg" onClick={() => setIsMobileMenuOpen(false)}>
            Lend
          </Link>
          <Link href="/trade" className="py-3 w-full text-center hover:bg-emerald-500/5 rounded-lg" onClick={() => setIsMobileMenuOpen(false)}>
            Trade
          </Link>
          <Link href="/yield" className={`py-3 w-full text-center rounded-lg ${isActive("/yield") ? "text-emerald-400 font-bold" : ""}`} onClick={() => setIsMobileMenuOpen(false)}>
            Yield
          </Link>

          <div className="w-full h-px bg-white/10 my-4"></div>

          <ConnectButton showBalance={false} accountStatus="address" chainStatus="icon" />
        </div>
      )}
    </div>
  );
};

export const Navbar = dynamic(() => Promise.resolve(NavbarComponent), { ssr: false });